def main():
    out = Path(__file__).parent
    payload = {"examples": [{k: v for k, v in ex.items() if k != "message_id"} for ex in EXAMPLES]}
    (out / "parsing-examples-cursor.json").write_text(
        json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8"
    )

    lines = []
    total_cards = 0
    for ex in EXAMPLES:
        lines.append(f"===== {ex['id']} =====")
        lines.append("TEXT:")
        lines.append(ex["text"])
        lines.append("")
        lines.append(f"MESSAGE_ID: {ex['message_id']}")
        lines.append("")
        if ex.get("tags"):
            lines.append("TAGS: " + ", ".join(ex["tags"]))
            lines.append("")
        if ex.get("entities"):
            lines.append("ENTITIES:")
            for ent_item in ex["entities"]:
                t = ent_item.get("type") or "(no type)"
                lines.append(f"  - {ent_item['name']} [{t}]")
            lines.append("")
        lines.append("CARDS:")
        for i, card in enumerate(ex["cards"], 1):
            total_cards += 1
            lines.append(f"[{i}]")
            lines.append("Q: " + card["question"])
            lines.append("A: " + card["answer"])
            if card.get("logic"):
                lines.append("LOGIC: " + card["logic"])
            lines.append("")
        lines.append("---")
        lines.append("")
    (out / "parsing-examples-cursor.txt").write_text("\n".join(lines), encoding="utf-8")

    readme = f"""# Cursor batch run-010

**50** сообщений (seed=42). Карточки из run-009; **`entities`** — объекты `{{name, type}}`.

Правила: [`quizlet-rules.md`](../../hermes/quizlet-rules.md). Типы: [`text_parsing_guide.md`](../../docs/text_parsing_guide.md).

Golden overlay: `apelsinovaya-sdelka` из [`parsing-examples.json`](../../parsing-examples/parsing-examples.json).

## Статистика

- **50** examples, **{total_cards}** cards
- Источник: [`candidates.json`](candidates.json)

## Новое в run-010 (vs run-009)

| Изменение | Описание |
|-----------|----------|
| `entities[].type` | YEAR, PERSONALIA_MALE, COUNTRY, … или `""` если не определимо |
| `apelsinovaya-sdelka` | Golden typed entities verbatim |
| Карточки | Без изменений (run-009) |

## Файлы

| Файл | Описание |
|------|----------|
| `parsing-examples-cursor.json` | 50 examples с typed entities |
| `parsing-examples-cursor.txt` | TXT + ENTITIES[name, type] |
| `build_output.py` | Источник EXAMPLES |
| `lint_cards.py` | Per-pair lint + type validation |
"""
    (out / "README.md").write_text(readme, encoding="utf-8")
    print(f"examples: {len(EXAMPLES)}, cards: {total_cards}")


if __name__ == "__main__":
    main()
